proof fn phi_1_empty_arch_satisfies_inv()
    ensures
        exists|a: Arch| a.layers.len() == 0 && a.inv(),
{
    let a = Arch { layers: Seq::empty() };
    assert(a.inv());
}

proof fn phi_3_inv_allows_unit_entry_size()
    ensures
        exists|a: Arch|
            a.inv() && a.layers.len() > 0 && a.entry_size(0) == 1,
{
    let layer = ArchLayer { entry_size: 1, num_entries: 1 };
    let a = Arch { layers: seq![layer] };
    assert(a.entry_size(0) == 1);
    assert(a.inv());
}

proof fn phi_4_inv_allows_single_entry_layer()
    ensures
        exists|a: Arch|
            a.inv() && a.layers.len() > 0 && a.num_entries(0) == 1,
{
    let layer = ArchLayer { entry_size: 1, num_entries: 1 };
    let a = Arch { layers: seq![layer] };
    assert(a.num_entries(0) == 1);
    assert(a.inv());
}

proof fn phi_5_entry_size_next_layer_vacuous_single()
    ensures
        exists|a: Arch|
            a.inv() && a.layers.len() == 1
            && a.entry_size(0) != a.entry_size(0) * a.num_entries(0),
{
    let layer = ArchLayer { entry_size: 3, num_entries: 2 };
    let a = Arch { layers: seq![layer] };
    assert(a.entry_size_is_next_layer_size(0));
    assert(a.inv());
    assert(a.entry_size(0) != a.entry_size(0) * a.num_entries(0));
}
